oxy_webhelp_navlinks = {"plan_agent_cloud_deployment-d30753e50792":{"topics":[{"title":"<span class=\"ph\">Agent Cloud<\/span> prerequisites","shortdesc":"<p class=\"shortdesc\">Confirm your <span class=\"ph\">RSC<\/span> environment meets these requirements before setting         up <span class=\"ph\">Agent Cloud<\/span>.<\/p>","href":"agent_cloud\/agent_cloud_prerequisites.html","attributes":{"data-id":"agent_cloud_prerequisites"},"menu":{"hasChildren":false},"tocID":"agent_cloud_prerequisites-d30753e50809","topics":[]},{"title":"Best practices for AI agents managed by <span class=\"ph\">Agent Cloud<\/span>","shortdesc":"<p class=\"shortdesc\">Before connecting AI agents to <span class=\"ph\">Agent Cloud<\/span>, review these best practices. Applying them during development and configuration — rather than after — ensures <span class=\"ph\">Agent Cloud<\/span> can accurately monitor, govern, and trace the actions of your agents.<\/p>","href":"agent_cloud\/agent_cloud_best_practices.html","attributes":{"data-id":"agent_cloud_best_practices"},"menu":{"hasChildren":false},"tocID":"agent_cloud_best_practices-d30753e50828","topics":[]},{"title":"Choose your data plane","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Agent Cloud<\/span>'s data plane — the component that processes agent traffic         and enforces policies — runs either as a Rubrik-managed SaaS service or inside your own AWS         or Azure VPC. Choose the option that fits your data residency requirements, cost model, and         infrastructure.<\/p>","href":"agent_cloud\/agent_cloud_deployment_provisioning_options.html","attributes":{"data-id":"agent_cloud_deployment_provisioning_options"},"menu":{"hasChildren":false},"tocID":"agent_cloud_deployment_provisioning_options-d30753e50847","next":"agent_cloud_deployment_provisioning_options-d30753e50847"}]}};